function withTimeout(promise, ms) {
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`Timed out after ${ms}ms`)), ms)
  );
  return Promise.race([promise, timeout]);
}

// Usage: fail fast if the server takes more than 5 seconds
const data = await withTimeout(fetch('/api/slow-endpoint'), 5000);

// Note: the original fetch continues running — use AbortController to cancel it:
function withTimeout(promise, ms, signal) {
  const controller = new AbortController();
  const timeout = new Promise((_, reject) => {
    const id = setTimeout(() => {
      controller.abort();
      reject(new Error(`Timed out after ${ms}ms`));
    }, ms);
    signal?.addEventListener('abort', () => clearTimeout(id));
  });
  return Promise.race([promise(controller.signal), timeout]);
}

async function sendBulkEmails(recipients) {
  const results = await Promise.allSettled(
    recipients.map(r => sendEmail(r.address, r.subject, r.body))
  );

  const succeeded = [];
  const failed    = [];

  results.forEach((result, i) => {
    if (result.status === 'fulfilled') {
      succeeded.push(recipients[i].address);
    } else {
      failed.push({ address: recipients[i].address, reason: result.reason.message });
    }
  });

  return { succeeded, failed };
  // Returns even if some emails failed — no silent partial failures
}

async function fetchFromFastest(endpoints) {
  try {
    // Try all CDN mirrors simultaneously; use whichever responds first
    const data = await Promise.any(
      endpoints.map(url => fetch(url).then(r => r.json()))
    );
    return data;
  } catch (err) {
    // AggregateError — every endpoint failed
    console.error('All sources failed:', err.errors);
    throw err;
  }
}

