async function syncUserData(userIds) {
  const results = await Promise.allSettled(
    userIds.map(id => syncUser(id))
  );

  const summary = {
    total:     results.length,
    succeeded: results.filter(r => r.status === 'fulfilled').length,
    failed:    results.filter(r => r.status === 'rejected').length,
    errors:    results
      .filter(r => r.status === 'rejected')
      .map(r => r.reason.message),
  };

  console.log(`Sync complete: ${summary.succeeded}/${summary.total} succeeded`);
  return summary;
}

import { useState, useEffect } from 'react';

function Dashboard({ userId }) {
  const [data, setData]       = useState({ user: null, posts: null, stats: null });
  const [errors, setErrors]   = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const controller = new AbortController();
    const sig = controller.signal;

    async function load() {
      const [userRes, postsRes, statsRes] = await Promise.allSettled([
        fetch(`/api/users/${userId}`,        { signal: sig }).then(r => r.json()),
        fetch(`/api/users/${userId}/posts`,  { signal: sig }).then(r => r.json()),
        fetch(`/api/users/${userId}/stats`,  { signal: sig }).then(r => r.json()),
      ]);

      if (sig.aborted) return;

      setData({
        user:  userRes.status  === 'fulfilled' ? userRes.value  : null,
        posts: postsRes.status === 'fulfilled' ? postsRes.value : null,
        stats: statsRes.status === 'fulfilled' ? statsRes.value : null,
      });
      setErrors({
        user:  userRes.status  === 'rejected' ? userRes.reason.message  : null,
        posts: postsRes.status === 'rejected' ? postsRes.reason.message : null,
        stats: statsRes.status === 'rejected' ? statsRes.reason.message : null,
      });
      setLoading(false);
    }

    load();
    return () => controller.abort();
  }, [userId]);

  if (loading) return <p>Loading dashboard…</p>;
  return (
    <div>
      {errors.user  ? <p>User error: {errors.user}</p>  : <UserCard  user={data.user}  />}
      {errors.posts ? <p>Posts error: {errors.posts}</p> : <PostList  posts={data.posts} />}
      {errors.stats ? <p>Stats error: {errors.stats}</p> : <StatsPanel stats={data.stats} />}
    </div>
  );
}

